import { apiService } from './apiService';

// Subscription Plans API - Using the comprehensive apiService
export const subscriptionService = {
  // Get available subscription plans
  getPlans: async () => {
    try {
      console.log('📡 Calling apiService.getSubscriptionPlans()...');
      const plans = await apiService.getSubscriptionPlans();
      console.log('📦 Received plans from API:', plans);
      const result = { success: true, data: plans };
      console.log('✅ Returning from getPlans():', result);
      return result;
    } catch (error) {
      console.error('❌ Error in getPlans():', error);
      throw error;
    }
  },

  // Get current user's subscription
  getCurrentSubscription: async () => {
    try {
      const subscription = await apiService.getCurrentSubscription();
      return { success: true, data: subscription };
    } catch (error) {
      throw error;
    }
  },

  // Create a new subscription
  createSubscription: async (plan, billingCycle) => {
    try {
      console.log('🔐 Checking authentication...');
      const token = localStorage.getItem('adminToken') || localStorage.getItem('token');
      if (!token) {
        throw new Error('Authentication required');
      }

      // Get API URL - window.configs.apiUrl does NOT include /api for localhost
      const baseUrl = window?.configs?.apiUrl || 'http://localhost:5001';
      const apiUrl = `${baseUrl}/api`;
      console.log(`📡 Calling API: POST ${apiUrl}/subscriptions/create`);
      console.log('📦 Request body:', { plan, billingCycle });

      const response = await fetch(`${apiUrl}/subscriptions/create`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({ plan, billingCycle }),
      });

      const data = await response.json();
      console.log('📨 API Response:', data);
      console.log('📊 Response status:', response.status);

      if (!response.ok) {
        console.error('❌ API Error:', data);
        throw new Error(data.message || 'Failed to create subscription');
      }

      console.log('✅ Subscription created successfully');
      return { success: true, subscription: data.subscription };
    } catch (error) {
      console.error('❌ Error in createSubscription:', error);
      throw error;
    }
  },

  // Upgrade subscription plan
  upgradeSubscription: async (plan, billingCycle) => {
    try {
      // This would need to be added to apiService if not already present
      throw new Error('Upgrade subscription functionality needs to be implemented in apiService');
    } catch (error) {
      throw error;
    }
  },

  // Cancel subscription
  cancelSubscription: async (reason) => {
    try {
      await apiService.cancelSubscription();
      return { success: true, message: 'Subscription cancelled successfully' };
    } catch (error) {
      throw error;
    }
  },

  // Get subscription usage statistics
  getUsage: async () => {
    try {
      // This would need to be added to apiService if not already present
      throw new Error('Get usage functionality needs to be implemented in apiService');
    } catch (error) {
      throw error;
    }
  },

  // Get user's payment history
  getPayments: async (page = 1, limit = 10) => {
    try {
      const payments = await apiService.getPayments();
      return { success: true, data: payments };
    } catch (error) {
      throw error;
    }
  },

  // Get payment invoice
  getInvoice: async (paymentId) => {
    try {
      // This would need to be added to apiService if not already present
      throw new Error('Get invoice functionality needs to be implemented in apiService');
    } catch (error) {
      throw error;
    }
  },
};

// Payment API - Using the comprehensive apiService
export const paymentService = {
  // Create a new payment
  createPayment: async (subscriptionId, paymentMethod, amount, gatewayResponse = {}) => {
    try {
      const token = localStorage.getItem('adminToken') || localStorage.getItem('token');
      if (!token) {
        throw new Error('Authentication required');
      }

      // Get API URL - window.configs.apiUrl does NOT include /api for localhost
      const baseUrl = window?.configs?.apiUrl || 'http://localhost:5001';
      const apiUrl = `${baseUrl}/api`;
      const response = await fetch(`${apiUrl}/payments/create`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({ subscriptionId, paymentMethod, amount, gatewayResponse }),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message || 'Failed to create payment');
      }

      return { success: true, payment: data.payment };
    } catch (error) {
      throw error;
    }
  },

  // Mark payment as completed
  completePayment: async (paymentId, gatewayTransactionId, gatewayResponse = {}) => {
    try {
      const token = localStorage.getItem('adminToken') || localStorage.getItem('token');
      if (!token) {
        throw new Error('Authentication required');
      }

      // Get API URL - window.configs.apiUrl does NOT include /api for localhost
      const baseUrl = window?.configs?.apiUrl || 'http://localhost:5001';
      const apiUrl = `${baseUrl}/api`;
      const response = await fetch(`${apiUrl}/payments/${paymentId}/complete`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({ gatewayTransactionId, gatewayResponse }),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message || 'Failed to complete payment');
      }

      return { success: true, payment: data.payment };
    } catch (error) {
      throw error;
    }
  },

  // Mark payment as failed
  failPayment: async (paymentId, reason) => {
    try {
      // This would need to be added to apiService if not already present
      throw new Error('Fail payment functionality needs to be implemented in apiService');
    } catch (error) {
      throw error;
    }
  },

  // Process refund
  processRefund: async (paymentId, amount, reason) => {
    try {
      // This would need to be added to apiService if not already present
      throw new Error('Process refund functionality needs to be implemented in apiService');
    } catch (error) {
      throw error;
    }
  },

  // Get payment details
  getPayment: async (paymentId) => {
    try {
      const payments = await apiService.getPayments();
      const payment = payments.find(p => p._id === paymentId);
      return { success: true, data: payment };
    } catch (error) {
      throw error;
    }
  },

  // Admin: Get payment statistics
  getPaymentStats: async (startDate, endDate) => {
    try {
      console.log('🔍 Getting payment stats...');
      const response = await apiService.getPaymentStats(startDate, endDate);
      console.log('📊 Payment stats received:', response);
      
      return response;
    } catch (error) {
      console.error('Error getting payment stats:', error);
      throw error;
    }
  },

  // Admin: Get recent payments
  getRecentPayments: async (limit = 10) => {
    try {
      console.log('🔍 Getting recent payments...');
      const response = await apiService.getRecentPayments(limit);
      console.log('📊 Recent payments received:', response);
      
      return response;
    } catch (error) {
      console.error('Error getting recent payments:', error);
      throw error;
    }
  },

  // Admin: Get all payments
  getAllPayments: async (page = 1, limit = 20, filters = {}) => {
    try {
      console.log('🔍 Getting all payments...', { page, limit, filters });
      const response = await apiService.getAllPayments(page, limit, filters);
      console.log('📊 All payments received:', response);
      
      return response;
    } catch (error) {
      console.error('Error getting all payments:', error);
      throw error;
    }
  },

  // Admin: Update payment status
  updatePaymentStatus: async (paymentId, status, notes = '') => {
    try {
      console.log('🔍 Updating payment status...', { paymentId, status, notes });
      
      const token = localStorage.getItem('adminToken') || localStorage.getItem('token');
      if (!token) {
        throw new Error('Authentication required');
      }

      // Get API URL - window.configs.apiUrl does NOT include /api for localhost
      const baseUrl = window?.configs?.apiUrl || 'http://localhost:5001';
      const apiUrl = `${baseUrl}/api`;
      const response = await fetch(`${apiUrl}/admin/payments/${paymentId}/status`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({ status, notes }),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || `HTTP error! status: ${response.status}`);
      }

      const data = await response.json();
      console.log('✅ Payment status updated:', data);
      
      return data;
    } catch (error) {
      console.error('Error updating payment status:', error);
      throw error;
    }
  },
};

export default subscriptionService;
